/**
 * Función de compatibilidad con el monolito.
 * En el nuevo stack, usa createApoloClient().odata() directamente.
 * @deprecated Usar createApoloClient
 */
export const requestApolo = async (entityName, filter, method, xrmContext) => {
  try {
    const url = xrmContext.Utility.getGlobalContext().getClientUrl()
    const response = await fetch(`${url}/api/data/v9.1/${entityName}?${filter}`, {
      method,
      headers: {
        'OData-MaxVersion': '4.0',
        'OData-Version': '4.0',
        'Content-Type': 'application/json; charset=utf-8',
        Accept: 'application/json',
        Prefer: 'odata.include-annotations=*',
      },
    })
    const data = await response.json()
    return data.value?.length > 0 ? data.value : null
  } catch {
    return null
  }
}
